/**
 * Error Handling Utilities
 *
 * APIエラーをユーザーフレンドリーなメッセージにマッピングする関数を提供します。
 * HTTPステータスコードとエラーレスポンスを解析し、適切なメッセージを返します。
 *
 * エラーマッピング:
 * - 400 Bad Request: バリデーションエラー
 * - 401 Unauthorized: 認証エラー
 * - 403 Forbidden: 権限エラー
 * - 404 Not Found: リソースが見つからない
 * - 409 Conflict: メール重複
 * - 423 Locked: アカウントロック
 * - 429 Too Many Requests: レート制限
 * - 500+ Server Error: サーバーエラー
 */

import { AxiosError } from 'axios';
import type { ApiError, ValidationErrorResponse } from '../types';

// ============================================================================
// Error Messages
// ============================================================================

/**
 * HTTPステータスコード別のデフォルトエラーメッセージ
 */
const defaultErrorMessages: Record<number, string> = {
  400: 'Invalid request. Please check your input.',
  401: 'Invalid email or password.',
  403: 'You do not have permission to perform this action.',
  404: 'The requested resource was not found.',
  409: 'This email is already registered.',
  423: 'Your account has been temporarily locked due to multiple failed login attempts.',
  429: 'Too many requests. Please try again later.',
  500: 'An internal server error occurred. Please try again.',
  502: 'Bad gateway. The server is temporarily unavailable.',
  503: 'Service unavailable. Please try again later.',
  504: 'Gateway timeout. Please try again.',
};

/**
 * 汎用エラーメッセージ（ステータスコードがマッピングされていない場合）
 */
const genericErrorMessage =
  'An unexpected error occurred. Please try again or contact support if the problem persists.';

// ============================================================================
// API Error Mapping
// ============================================================================

/**
 * APIエラーをユーザーフレンドリーなメッセージにマッピング
 * @param status - HTTPステータスコード
 * @param error - APIエラーレスポンス（オプション）
 * @returns ユーザーフレンドリーなエラーメッセージ
 */
export const mapApiErrorToMessage = (status: number, error?: ApiError): string => {
  // エラーレスポンスにカスタムメッセージがある場合はそれを使用
  if (error?.error) {
    return error.error;
  }

  // アカウントロックエラーの場合、ロック解除時刻を含める
  if (status === 423 && error?.lockedUntil) {
    const lockedUntil = new Date(error.lockedUntil);
    const formattedTime = lockedUntil.toLocaleTimeString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
    });
    return `Your account has been temporarily locked due to multiple failed login attempts. Please try again after ${formattedTime}.`;
  }

  // ステータスコード別のデフォルトメッセージ
  return defaultErrorMessages[status] || genericErrorMessage;
};

/**
 * バリデーションエラーレスポンスを解析してフィールドエラーにマッピング
 * @param errorResponse - バリデーションエラーレスポンス
 * @returns フィールドエラーオブジェクト { field: errorMessage }
 */
export const parseValidationErrors = (
  errorResponse: ValidationErrorResponse
): Record<string, string> => {
  const fieldErrors: Record<string, string> = {};

  if (errorResponse.errors && Array.isArray(errorResponse.errors)) {
    errorResponse.errors.forEach((error) => {
      fieldErrors[error.field] = error.message;
    });
  }

  return fieldErrors;
};

// ============================================================================
// Network Error Handling
// ============================================================================

/**
 * ネットワークエラーをハンドリング
 * Axiosエラー、ネットワークエラー、タイムアウトなどを解析します
 * @param error - キャッチされたエラー
 * @returns ユーザーフレンドリーなエラーメッセージ
 */
export const handleNetworkError = (error: unknown): string => {
  // AxiosErrorの場合
  if (error && typeof error === 'object' && 'isAxiosError' in error) {
    const axiosError = error as AxiosError<ApiError | ValidationErrorResponse>;

    // レスポンスがある場合（サーバーからエラーレスポンスが返された）
    if (axiosError.response) {
      const { status, data } = axiosError.response;

      // バリデーションエラー（400）の場合
      if (status === 400 && data && 'errors' in data) {
        const validationResponse = data as ValidationErrorResponse;
        const fieldErrors = parseValidationErrors(validationResponse);
        const errorMessages = Object.values(fieldErrors);
        return errorMessages.length > 0 ? errorMessages.join('. ') : data.error;
      }

      // その他のAPIエラー
      return mapApiErrorToMessage(status, data as ApiError);
    }

    // リクエストは送信されたがレスポンスがない場合（ネットワークエラー）
    if (axiosError.request) {
      return 'Network error. Please check your internet connection and try again.';
    }

    // リクエストの設定中にエラーが発生した場合
    return axiosError.message || genericErrorMessage;
  }

  // 通常のErrorオブジェクトの場合
  if (error instanceof Error) {
    return error.message;
  }

  // その他の未知のエラー
  return genericErrorMessage;
};

/**
 * エラーがタイムアウトかどうかを判定
 * @param error - キャッチされたエラー
 * @returns タイムアウトエラーの場合true
 */
export const isTimeoutError = (error: unknown): boolean => {
  if (error && typeof error === 'object' && 'code' in error) {
    return (error as { code: string }).code === 'ECONNABORTED';
  }
  return false;
};

/**
 * エラーがAxiosErrorかどうかを判定
 * @param error - キャッチされたエラー
 * @returns AxiosErrorの場合true
 */
export const isAxiosError = (error: unknown): error is AxiosError => {
  return error !== null && typeof error === 'object' && 'isAxiosError' in error;
};

/**
 * AxiosErrorからレスポンスステータスとデータを取得
 * @param error - AxiosError
 * @returns { status: number, data: unknown } または null
 */
export const getAxiosErrorResponse = (error: unknown): { status: number; data: unknown } | null => {
  if (isAxiosError(error) && error.response) {
    return {
      status: error.response.status,
      data: error.response.data,
    };
  }
  return null;
};

/**
 * エラーがネットワークエラーかどうかを判定
 * @param error - キャッチされたエラー
 * @returns ネットワークエラーの場合true
 */
export const isNetworkError = (error: unknown): boolean => {
  if (error && typeof error === 'object') {
    const axiosError = error as AxiosError;
    return axiosError.request !== undefined && axiosError.response === undefined;
  }
  return false;
};

/**
 * エラーが認証エラーかどうかを判定
 * @param error - キャッチされたエラー
 * @returns 認証エラー（401）の場合true
 */
export const isAuthError = (error: unknown): boolean => {
  if (error && typeof error === 'object' && 'response' in error) {
    const axiosError = error as AxiosError;
    return axiosError.response?.status === 401;
  }
  return false;
};

/**
 * エラーメッセージをトースト通知用に短縮
 * @param message - エラーメッセージ
 * @param maxLength - 最大文字数（デフォルト: 100）
 * @returns 短縮されたメッセージ
 */
export const truncateErrorMessage = (message: string, maxLength: number = 100): string => {
  if (message.length <= maxLength) {
    return message;
  }
  return `${message.substring(0, maxLength - 3)}...`;
};
